INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('3c278dd2-19cb-55b1-a1bd-df88661720af', '1bace421-9ec0-4623-921f-5e6b26d8dd8b', 'I use an ___ to wake me up every morning.', '我每天早上都用鬧鐘來叫醒我。', 'alarm clock', 'eraser', 'umbrella', 'apple', 'alarm (警報) + clock (時鐘)', 'alarm (警報) + clock (時鐘) → 鬧鐘'),
('52a051ab-ee3f-5535-9b6b-78924a47e443', '274ca5ba-aa7f-4abf-ac77-854aac1e695e', 'He ___ a red bag.', '他有一個紅色的包包。', 'has', 'wants', 'likes', 'needs', 'have 的第三人稱單數形式是 has。', '當主詞是 He/She/It 時，have 要變成 has。'),
('edc6b25e-85a5-5b0a-b4d6-bfe818f68c53', '78c8571f-9d90-4e82-9f1d-9eba115d2be3', 'We usually go to the park ___ the afternoon.', '我們通常在下午去公園。', 'in', 'on', 'at', 'by', '(介係詞) 用於特定的時間段 (例如：in the morning)。', '記住時間片段用 in。'),
('0c047f83-05f9-538e-bed1-54e1d39bf027', '527aeca3-cf9d-4fbc-987d-67a0bd2dd649', '___ you think the exam was difficult or easy?', '你覺得這次考試是很難還是很容易？', 'Do', 'Are', 'Have', 'Will', 'do 作為助動詞，用於構成一般疑問句。', '問動作用 Do，問狀態用 Are。'),
('12ad0a04-3fa3-5810-a50d-189558560b23', 'ab9949bb-c10f-4d67-8598-84d3e16ab7d5', 'I am very happy to be ___ you during this difficult time.', '在這段艱難的時期，能陪伴在你身邊我感到很開心。', 'with', 'by', 'in', 'on', '表示伴隨或在某人身邊。', '伴隨著某人。');
